        $translation_question_de = ['parent_id' => $faq_id, 'table_name' => 'faq', 'type' => 'question', 'language' => 'de', 'translation' => 'Wie verarbeitet ihr meine Zahlungsdaten?'];
        $translation_answer_de = ['parent_id' => $faq_id, 'table_name' => 'faq', 'type' => 'answer', 'language' => 'de', 'translation' => 'Wir leiten dich zur Zahlung an unseren Zahlungsdienstleister Stripe weiter. Dort kannst du deine Zahlungsdaten sicher eingeben. Wir speichern keine Zahlungsdaten auf unseren Servern, sondern erhalten nur die Information, dass die Zahlung erfolgreich war, damit wir dir die entsprechenden Vorteile deiner Mitgliedschaft freischalten können.'];
        $translation_question_en = ['parent_id' => $faq_id, 'table_name' => 'faq', 'type' => 'question', 'language' => 'en', 'translation' => 'How do you process my payment information?'];
        $translation_answer_en = ['parent_id' => $faq_id, 'table_name' => 'faq', 'type' => 'answer', 'language' => 'en', 'translation' => 'We redirect you to our payment service provider Stripe for payment. There you can securely enter your payment details. We do not store any payment data on our servers; we only receive information that the payment was successful so that we can unlock the corresponding benefits of your membership.'];
        $translation_question_es = ['parent_id' => $faq_id, 'table_name' => 'faq', 'type' => 'question', 'language' => 'es', 'translation' => '¿Cómo procesan mis datos de pago?'];
        $translation_answer_es = ['parent_id' => $faq_id, 'table_name' => 'faq', 'type' => 'answer', 'language' => 'es', 'translation' => 'Te redirigimos a nuestro proveedor de servicios de pago Stripe para el pago. Allí puedes ingresar tus datos de pago de forma segura. No almacenamos ningún dato de pago en nuestros servidores; solo recibimos la información de que el pago fue exitoso para poder desbloquear los beneficios correspondientes de tu membresía.'];
        $translation_question_fr = ['parent_id' => $faq_id, 'table_name' => 'faq', 'type' => 'question', 'language' => 'fr', 'translation' => 'Comment traitez-vous mes informations de paiement ?'];
        $translation_answer_fr = ['parent_id' => $faq_id, 'table_name' => 'faq', 'type' => 'answer', 'language' => 'fr', 'translation' => 'Nous vous redirigeons vers notre prestataire de services de paiement Stripe pour le paiement. Vous pouvez y saisir vos coordonnées bancaires en toute sécurité. Nous ne stockons aucune donnée de paiement sur nos serveurs ; nous recevons uniquement l\'information que le paiement a réussi afin de pouvoir débloquer les avantages correspondants de votre abonnement.'];
