        $translation_answer_es = ['parent_id' => $faq_id, 'table_name' => 'faq', 'type' => 'answer', 'language' => 'es', 'translation' => 'Una actualización (por ejemplo, de Bronce a Plata u Oro) entra en vigor de inmediato. Recibirás acceso inmediato a los beneficios del nivel de membresía superior y se te mostrará en consecuencia en la vista general de la tienda y en tu perfil. Una degradación (por ejemplo, de Oro a Plata o Bronce) entra en vigor al final del período ya pagado. Esto significa que conservarás los beneficios del nivel de membresía superior hasta el final del período de facturación actual y solo serás degradado al nivel inferior después de eso.'];
        $translation_question_fr = ['parent_id' => $faq_id, 'table_name' => 'faq', 'type' => 'question', 'language' => 'fr', 'translation' => 'Comment gérez-vous la montée et la descente en gamme de l\'abonnement ?'];
        $translation_answer_fr = ['parent_id' => $faq_id, 'table_name' => 'faq', 'type' => 'answer', 'language' => 'fr', 'translation' => 'Une montée en gamme (par exemple, de Bronze à Argent ou Or) prend effet immédiatement. Vous obtenez un accès immédiat aux avantages du niveau d\'abonnement supérieur et vous êtes affiché en conséquence dans l\'aperçu de la boutique et sur votre profil. Une descente en gamme (par exemple, d\'Or à Argent ou Bronze) prend effet à la fin de la période déjà payée. Cela signifie que vous conservez les avantages du niveau d\'abonnement supérieur jusqu\'à la fin de la période de facturation en cours et n\'êtes rétrogradé vers le niveau inférieur qu\'après.'];
        $translation_question_it = ['parent_id' => $faq_id, 'table_name' => 'faq', 'type' => 'question', 'language' => 'it', 'translation' => 'Come gestite l\'upgrade e il downgrade dell\'abbonamento?'];
        $translation_answer_it = ['parent_id' => $faq_id, 'table_name' => 'faq', 'type' => 'answer', 'language' => 'it', 'translation' => 'Un upgrade (ad esempio, da Bronzo ad Argento o Oro) diventa effettivo immediatamente. Otterrai immediatamente l\'accesso ai vantaggi del livello di abbonamento superiore e verrai visualizzato di conseguenza nella panoramica del negozio e nel tuo profilo. Un downgrade (ad esempio, da Oro ad Argento o Bronzo) diventa effettivo alla fine del periodo già pagato. Ciò significa che manterrai i vantaggi del livello di abbonamento superiore fino alla fine del periodo di fatturazione corrente e verrai declassato al livello inferiore solo dopo.'];
